head.script:
            scwin.onpageload = function() {
                scwin.loadFolders();
            };

            scwin.callApi = function(url, callback) {
                var xhr = new XMLHttpRequest();
                xhr.open("GET", url, true);
                xhr.onreadystatechange = function() {
                   if (xhr.readyState !== 4) { return; }
                    if (xhr.status >= 200 && xhr.status < 300) {
                        try {
                            callback(JSON.parse(xhr.responseText || "[]"));
                        } catch (e) {
                            console.error("[FileBrowser] JSON parse error", url, e);
                            callback([]);
                        }
                        } else {
                        console.error("[FileBrowser] HTTP error", xhr.status, url);
                        callback([]);
                    }
                };
                xhr.onerror = function() {
                    console.error("[FileBrowser] Network error", url);
                    callback([]);
                };
                xhr.send();
            };

            scwin.callApiJson = function(method, url, payload, callback) {
                var xhr = new XMLHttpRequest();
                xhr.open(method, url, true);
                xhr.setRequestHeader("Content-Type", "application/json; charset=UTF-8");
                xhr.onreadystatechange = function() {
                    if (xhr.readyState !== 4) { return; }
                    if (xhr.status >= 200 && xhr.status < 300) {
                        callback(JSON.parse(xhr.responseText || "{}"));
                    } else {
                        alert("Lưu thất bại. HTTP " + xhr.status);
                    }
                };
                xhr.send(JSON.stringify(payload || {}));
            };

            scwin._formatFileSize = function(bytes) {
                var n = parseFloat(bytes || 0);
                if (!n || n <= 0) { return "0 B"; }
                var kb = 1024;
                var mb = kb * 1024;
                var gb = mb * 1024;
                if (n >= gb) { return (n / gb).toFixed(2) + " GB"; }
                if (n >= mb) { return (n / mb).toFixed(2) + " MB"; }
                if (n >= kb) { return (n / kb).toFixed(2) + " KB"; }
                return n + " B";
            };

            scwin._FILE_ICON_COLORS = {
                "PDF": "#f44336", "DOC": "#1e88e5", "DOCX": "#1e88e5",
                "XLS": "#43a047", "XLSX": "#43a047", "PPT": "#ff7043", "PPTX": "#ff7043",
                "JPG": "#43a047", "JPEG": "#43a047", "PNG": "#1e88e5",
                "GIF": "#8e24aa", "SVG": "#00897b", "PSD": "#5e35b1",
                "MP4": "#fb8c00", "MOV": "#f4511e", "AVI": "#f4511e",
                "MP3": "#3949ab", "WAV": "#3949ab", "AAC": "#3949ab",
                "ZIP": "#546e7a", "RAR": "#546e7a", "7Z": "#546e7a"
            };

            scwin._makeFileIcon = function(ext) {
                var color = scwin._FILE_ICON_COLORS[ext] || "#546e7a";
                var lbl = String(ext || "FILE").substring(0, 4);
                var svg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 40">'
                    + '<path d="M2,0 L22,0 L32,10 L32,40 L2,40 Z" fill="#ffffff" stroke="#d1d5db" stroke-width="1.5"/>'
                    + '<path d="M22,0 L22,10 L32,10 Z" fill="#e5e7eb"/>'
                    + '<rect x="2" y="26" width="30" height="14" fill="' + color + '"/>'
                    + '<text x="16" y="37" font-family="Arial,sans-serif" font-size="8" font-weight="bold" fill="#ffffff" text-anchor="middle">' + lbl + '</text>'
                    + '</svg>';
                return "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
            };

            scwin._styleIconBadges = function() {
                try {
                    var cells = document.querySelectorAll(".dam-asset-grid-view .dam-cell-icon");
                    for (var i = 0; i < cells.length; i++) {
                        var cell = cells[i];
                        var labelEl = cell.querySelector(".w2grid_label");
                        var ext = (labelEl ? (labelEl.textContent || labelEl.innerText || "") : (cell.textContent || "")).trim().toUpperCase().replace(".", "");
                        if (!ext) { ext = "FILE"; }
                        if (labelEl) { labelEl.style.cssText = "display:none!important;visibility:hidden!important;"; }
                        var existingImg = cell.querySelector(".dam-icon-img");
                        if (existingImg) {
                            if (existingImg.alt === ext) { continue; }
                            existingImg.parentNode.removeChild(existingImg);
                        }
                        var img = document.createElement("img");
                        img.className = "dam-icon-img";
                        img.src = scwin._makeFileIcon(ext);
                        img.alt = ext;
                        img.style.cssText = "width:28px;height:34px;object-fit:contain;display:block;margin:0 auto;pointer-events:none;";
                        cell.appendChild(img);
                    }
                } catch (e) {}
            };

            scwin.grdAsset_ondrawendrow = function() {
                scwin._styleIconBadges();
            };

            scwin._ASSET_TYPE_VALUES = {
                "Documents": true,
                "Images": true,
                "Videos": true,
                "Audio": true
            };

            scwin._STATUS_VALUES = {
                "Draft": true,
                "Published": true,
                "Archived": true
            };

            scwin._normalizeEnumValue = function(value, allowed, fallback) {
                var val = value == null ? "" : String(value);
                return allowed[val] ? val : (fallback || "");
            };

            scwin._inferAssetType = function(fileType, fileExt) {
                var normalized = scwin._normalizeEnumValue(fileType, scwin._ASSET_TYPE_VALUES, "");
                if (normalized) { return normalized; }
                var ext = String(fileExt || "").toLowerCase().replace(".", "");
                var documents = { pdf: true, doc: true, docx: true, xls: true, xlsx: true, ppt: true, pptx: true };
                var images = { jpg: true, jpeg: true, png: true, gif: true, svg: true, psd: true };
                var videos = { mp4: true, mov: true, avi: true };
                var audio = { mp3: true, wav: true, aac: true };
                if (documents[ext]) { return "Documents"; }
                if (images[ext]) { return "Images"; }
                if (videos[ext]) { return "Videos"; }
                if (audio[ext]) { return "Audio"; }
                return "";
            };

            scwin._forceSelectValue = function(compId, value) {
                var val = value == null ? "" : String(value);
                try {
                    var roots = [];
                    var exact = document.getElementById(compId);
                    if (exact) { roots.push(exact); }
                    var prefixed = document.querySelectorAll('[id^="' + compId + '"]');
                    for (var i = 0; i < prefixed.length; i++) { roots.push(prefixed[i]); }
                    for (var r = 0; r < roots.length; r++) {
                        var root = roots[r];
                        var selects = root.tagName && root.tagName.toLowerCase() === "select"
                            ? [root]
                            : root.querySelectorAll ? root.querySelectorAll("select") : [];
                        for (var s = 0; s < selects.length; s++) {
                            selects[s].value = val;
                            if (selects[s].value !== val) {
                                for (var o = 0; o < selects[s].options.length; o++) {
                                    if (selects[s].options[o].value === val || selects[s].options[o].text === val) {
                                        selects[s].selectedIndex = o;
                                        break;
                                    }
                                }
                            }
                            selects[s].dispatchEvent(new Event("change", { bubbles: true }));
                            selects[s].dispatchEvent(new Event("input", { bubbles: true }));
                        }
                    }
                } catch (e) {}
            };

            scwin._setDetailField = function(compId, key, value) {
                var val = value == null ? "" : String(value);
                dmAssetDetail.set(key, val);
                try {
                    var el = document.getElementById(compId);
                    if (el && ("value" in el)) { el.value = val; }
                } catch (e) {}
                try {
                    var comp = $p.getComponentById(compId);
                    if (comp && typeof comp.setValue === "function") {
                        comp.setValue(val);
                    }
                } catch (e) {}
                if (compId === "inpFileType" || compId === "selAssetData") {
                    scwin._forceSelectValue(compId, val);
                    window.setTimeout(function() { scwin._forceSelectValue(compId, val); }, 80);
                }
            };

            scwin._clearAssetDetail = function() {
                 scwin._setDetailField("inpFileNm", "FILE_NM", "");
                scwin._setDetailField("taDescription", "DESCRIPTION", "");
                scwin._setDetailField("inpFileType", "FILE_TYPE", "");
                scwin._setDetailField("inpTags", "TAGS", "");
                scwin._setDetailField("selAssetData", "STATUS", "Draft");
                scwin._setDetailField("inpFileSize", "FILE_SIZE", "");
                scwin._setDetailField("inpOwnerNm", "OWNER_NM", "");
                 scwin._setDetailField("taChangeLog", "CHANGE_LOG", "");
                scwin._setDetailField("inpUploadDt", "UPLOAD_DT", "");
            };

            scwin._realRowIndex = function(displayRow) {
                if (displayRow == null || displayRow < 0) { return -1; }
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (grd && typeof grd.getRealRowIndex === "function") {
                        return grd.getRealRowIndex(displayRow);
                    }
                } catch (e) {}
                return displayRow;
            };

            scwin._applyDetailFromGridRow = function(rowData) {
                if (!rowData) { return; }
                var fileType = scwin._inferAssetType(rowData.FILE_TYPE, rowData.ICON || rowData.FILE_EXT);
                var st = scwin._normalizeEnumValue(rowData.STATUS, scwin._STATUS_VALUES, "Draft");
                scwin._setDetailField("inpFileNm", "FILE_NM", rowData.FILE_NM || "");
                scwin._setDetailField("inpFileType", "FILE_TYPE", fileType);
                scwin._setDetailField("inpFileSize", "FILE_SIZE", rowData.FILE_SIZE || "");
                scwin._setDetailField("selAssetData", "STATUS", st);
                scwin._setDetailField("taDescription", "DESCRIPTION", rowData.DESCRIPTION || "");
                scwin._setDetailField("inpTags", "TAGS", rowData.TAGS || "");
                scwin._setDetailField("inpOwnerNm", "OWNER_NM", rowData.OWNER_NM || "");
                scwin._setDetailField("inpUploadDt", "UPLOAD_DT", rowData.UPLOAD_DT || "");
            };

            scwin._selectRowAndShowDetail = function(displayRowIndex) {
                var ri = scwin._realRowIndex(displayRowIndex);
                if (ri < 0) { return; }
                var rowData = dlAsset.getRowJSON(ri);
                if ((!rowData || rowData.ASSET_ID == null || rowData.ASSET_ID === "") && displayRowIndex >= 0) {
                    rowData = dlAsset.getRowJSON(displayRowIndex);
                }
                if (!rowData || rowData.ASSET_ID == null || rowData.ASSET_ID === "") { return; }
                scwin._applyDetailFromGridRow(rowData);
                 scwin._selectedAssetId = rowData.ASSET_ID;
                scwin.loadAssetDetail(rowData.ASSET_ID, rowData);
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (grd && typeof grd.setSelectedIndex === "function") {
                        grd.setSelectedIndex(displayRowIndex);
                    }
                 } catch (e) {}
	            };

	            scwin._buildFolderRows = function(folders) {
	                var list = folders || [];
	                var childrenMap = {};
	                var allIds = {};
	                for (var i = 0; i < list.length; i++) {
	                    var id = list[i].folderId != null ? list[i].folderId : list[i].FOLDER_ID;
	                    allIds[id] = true;
	                }
	                for (var j = 0; j < list.length; j++) {
	                    var item = list[j];
	                    var pid = item.parentFolderId != null ? item.parentFolderId : item.PARENT_FOLDER_ID;
	                    if (!pid) { pid = 0; }
	                    if (!childrenMap[pid]) { childrenMap[pid] = []; }
	                    childrenMap[pid].push(item);
	                }
	                var roots = [];
	                for (var k = 0; k < list.length; k++) {
	                    var f = list[k];
	                    var parentId = f.parentFolderId != null ? f.parentFolderId : f.PARENT_FOLDER_ID;
	                    if (!parentId || !allIds[parentId]) { roots.push(f); }
	                }
	                var rows = [];
	                var visit = function(node, depth) {
	                    var nodeId = node.folderId != null ? node.folderId : node.FOLDER_ID;
	                    rows.push({
	                        FOLDER_ID: String(nodeId),
	                        FOLDER_NM: node.folderNm || node.FOLDER_NM || "",
	                        DEPTH: String(depth)
	                    });
	                    var children = childrenMap[nodeId] || [];
	                    for (var n = 0; n < children.length; n++) {
	                        visit(children[n], depth + 1);
	                    }
	                };
	                for (var r = 0; r < roots.length; r++) { visit(roots[r], 1); }
	                return rows;
	            };
	            scwin.buildFolderRows = scwin._buildFolderRows;

            scwin.loadFolders = function() {
                scwin.callApi("/api/dam/folders", function(folders) {
                    if (!folders || !folders.length) {
                     dlFolder.setJSON([]);
                        dlAsset.setJSON([]);
                        scwin._clearAssetDetail();
                        return;
                    }
                                        var buildRowsFn = (typeof scwin._buildFolderRows === "function")
	                        ? scwin._buildFolderRows
	                        : (typeof scwin.buildFolderRows === "function" ? scwin.buildFolderRows : null);
	                    if (typeof buildRowsFn !== "function") {
	                        console.error("[FileBrowser] buildFolderRows function is missing");
	                        dlFolder.setJSON([]);
	                        return;
	                    }
	                    var rows = buildRowsFn(folders);
                    dlFolder.setJSON(rows);
                    window.setTimeout(function() {
                        try { trvFolder.expandAll(); } catch (e) {}
                    }, 100);

                    scwin._loadFirstFolderWithAssets(folders, 0);
                });
            };

            scwin._loadFirstFolderWithAssets = function(folders, index) {
                if (!folders || index >= folders.length) {
                    dlAsset.setJSON([]);
                    scwin._clearAssetDetail();
                    return;
                }
                var folder = folders[index];
                var folderId = folder.folderId != null ? folder.folderId : folder.FOLDER_ID;
                if (folderId == null) {
                    scwin._loadFirstFolderWithAssets(folders, index + 1);
                    return;
                }
                scwin.callApi("/api/dam/assets?folderId=" + encodeURIComponent(folderId), function(list) {
                    if (list && list.length > 0) {
                        dmFolder.set("FOLDER_ID", String(folderId));
                        dmFolder.set("FOLDER_NM", folder.folderNm || folder.FOLDER_NM || "");
                        scwin.loadAssets(folderId);
                    } else {
                        scwin._loadFirstFolderWithAssets(folders, index + 1);
                    }
                });
            };
            scwin.loadAssetsByFolder = function() {
                var folderId = dmFolder.get("FOLDER_ID");
                if (folderId == null || folderId === "") {
                    try { folderId = trvFolder.getSelectedValue(); } catch (e) {}
                }
                var parsedFolderId = parseInt(folderId, 10);
                if (isNaN(parsedFolderId)) {
                    console.warn("[FileBrowser] Cannot reload assets because folderId is missing", folderId);
                    return;
                }
                dmFolder.set("FOLDER_ID", String(parsedFolderId));
                scwin.loadAssets(parsedFolderId);
            };

            scwin.loadAssets = function(folderId) {
                scwin.callApi("/api/dam/assets?folderId=" + encodeURIComponent(folderId), function(list) {
                    var rows = [];
                    for (var i = 0; i < (list || []).length; i++) {
                        var item = list[i];
                        rows.push({
                            "CHK": "",
                            "ASSET_ID": item.assetId,
                            "ICON": item.fileExt ? String(item.fileExt).toUpperCase() : (item.fileType || ""),
                            "FILE_NM": item.fileNm || "",
                            "FILE_TYPE": item.fileType || "",
                            "FILE_SIZE": scwin._formatFileSize(item.fileSize),
                            "STATUS": item.status || "Draft",
                            "TAGS": item.tags || "",
                            "DESCRIPTION": item.description || "",
                            "OWNER_NM": item.ownerNm || "",
                            "UPLOAD_DT": item.uploadDt || ""
                        });
                    }
                    dlAsset.setJSON(rows);
                    if (rows.length > 0) {
                        window.setTimeout(function() { scwin._styleIconBadges(); }, 100);
                        window.setTimeout(function() { scwin._styleIconBadges(); }, 500);
                        scwin._applyDetailFromGridRow(rows[0]);
                        scwin.loadAssetDetail(rows[0].ASSET_ID, rows[0]);
                        window.setTimeout(function() {
                            try {
                                var grd = $p.getComponentById("grdAsset");
                                if (grd && typeof grd.setSelectedIndex === "function") {
                                    grd.setSelectedIndex(0);
                                }
                            } catch (e) {}
                        }, 50);
                    } else {
                        scwin._clearAssetDetail();
                    }
                });
            };

              scwin.trvFolder_onclick = function() {
                var folderId = parseInt(trvFolder.getSelectedValue(), 10);
                if (isNaN(folderId)) { return; }
                dmFolder.set("FOLDER_ID", String(folderId));
                scwin.loadAssets(folderId);
            };

            scwin._normalizeRowIndex = function(rowLike) {
                var row = rowLike;
                if (row && typeof row === "object") {
                    if (typeof row.rowIndex === "number") { row = row.rowIndex; }
                    else if (typeof row.newRowIndex === "number") { row = row.newRowIndex; }
                    else if (typeof row.index === "number") { row = row.index; }
                }
                row = parseInt(row, 10);
                if (isNaN(row) || row < 0) { return -1; }
                return row;
            };
            scwin.grdAsset_onrowindexchange = function(row, oldRow) {
                 var newRow = scwin._normalizeRowIndex(row);
                if (newRow < 0 && arguments.length >= 3) {
                    newRow = scwin._normalizeRowIndex(arguments[2]);
                }
                if (newRow < 0) { return; }
                scwin._selectRowAndShowDetail(newRow);
            };

            /* Khi focus ô đổi hàng (chuột / phím), đồng bộ panel phải */
            scwin.grdAsset_oncellindexchange = function(row, col, oldRow, oldCol) {
                 var newRow = scwin._normalizeRowIndex(row);
                var prevRow = scwin._normalizeRowIndex(oldRow);
                if (newRow < 0 && arguments.length >= 3) {
                    prevRow = scwin._normalizeRowIndex(arguments[1]);
                    newRow = scwin._normalizeRowIndex(arguments[2]);
                }
                if (newRow < 0 || newRow === prevRow) { return; }
                scwin._selectRowAndShowDetail(newRow);
            };

            scwin.grdAsset_oncellclick = function(row, col, colId) {
                 window.setTimeout(function() {
                    var newRow = -1;
                    try {
                        var grd = $p.getComponentById("grdAsset");
                        if (grd && typeof grd.getFocusedRowIndex === "function") {
                            newRow = scwin._normalizeRowIndex(grd.getFocusedRowIndex());
                        }
                    } catch (e) {}

                    if (newRow < 0) {
                        newRow = scwin._normalizeRowIndex(row);
                    }
                    if (newRow < 0) { return; }
                    if (colId && String(colId).indexOf("hd") === 0) { return; }
                    // Chỉ hiển thị thông tin item được chọn. Popup upload mở bằng double-click.
                    scwin._selectRowAndShowDetail(newRow);
                }, 30);
            };

            scwin.loadAssetDetail = function(assetId, fallbackRow) {
                scwin.callApi("/api/dam/assets/" + encodeURIComponent(assetId), function(response) {
                    var base = fallbackRow || {};
                    if (!response || !response.asset) {
                        scwin._applyDetailFromGridRow(base);
                        scwin._setDetailField("taDescription", "DESCRIPTION", "");
                        scwin._setDetailField("inpTags", "TAGS", "");
                        scwin._setDetailField("taChangeLog", "CHANGE_LOG", "");
                        return;
                    }
                    var asset = response.asset;
                    var fileType = scwin._inferAssetType(asset.fileType || base.FILE_TYPE, asset.fileExt || base.ICON || base.FILE_EXT);
                    var status = scwin._normalizeEnumValue(asset.status || base.STATUS, scwin._STATUS_VALUES, "Draft");
                    var latestVersion = scwin._pickLatestVersion(response.versions || []);
                    var latestVersionUploadDt = latestVersion && latestVersion.uploadDt ? latestVersion.uploadDt : "";
                    scwin._setDetailField("inpFileNm", "FILE_NM", asset.fileNm || base.FILE_NM || "");
                    scwin._setDetailField("taDescription", "DESCRIPTION", asset.description || base.DESCRIPTION || "");
                    scwin._setDetailField("inpFileType", "FILE_TYPE", fileType);
                    scwin._setDetailField("inpTags", "TAGS", asset.tags || base.TAGS || "");
                    scwin._setDetailField("selAssetData", "STATUS", status);
                    var sz = "";
                    if (asset.fileSize != null && typeof asset.fileSize === "number") {
                        sz = scwin._formatFileSize(asset.fileSize);
                    } else {
                        sz = base.FILE_SIZE || "";
                    }
                    scwin._setDetailField("inpFileSize", "FILE_SIZE", sz);
                    scwin._setDetailField("inpOwnerNm", "OWNER_NM", asset.ownerNm || base.OWNER_NM || "");
                    scwin._setDetailField("taChangeLog", "CHANGE_LOG", "");
                    scwin._setDetailField("inpUploadDt", "UPLOAD_DT", latestVersionUploadDt || base.UPLOAD_DT || asset.uploadDt || "");
                });
            };

            scwin.grdAsset_oncelldblclick = function(row, col, colId) {
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (!grd) { return; }
                    var ri = grd.getRealRowIndex(row);
                    var rowData = dlAsset.getRowJSON(ri);
                    if (rowData && rowData.ASSET_ID) {
                        scwin.openAssetPopup(Number(rowData.ASSET_ID));
                    }
                } catch (e) {
                    console.warn("[FileBrowser] oncelldblclick", e);
                }
            };

            scwin.openAssetPopup = function(assetId) {
                if (!assetId) { return; }
                 scwin._openInlineUploadPopup({ assetId: assetId });
            };

            scwin._applyPopupPreview = function(url) {
                var u = url || "/cm/dam/images/preview/document.svg";
                try {
                    var img = $p.getComponentById("img_fb_popup_preview");
                    if (img && typeof img.setSrc === "function") { img.setSrc(u); }
                } catch (e) {}
            };


             scwin._versionSortValue = function(ver) {
                if (!ver) { return -1; }
                var raw = String(ver).trim();
                if (!raw) { return -1; }
                var m = raw.match(/^(?:v|V)?(\d+)(?:\.(\d+))?$/);
                if (m) {
                    var major = parseInt(m[1], 10) || 0;
                    var minor = parseInt(m[2] || "0", 10) || 0;
                    return (major * 1000000) + minor;
                }
                var n = parseFloat(raw.replace(/^[vV]/, ""));
                return isNaN(n) ? -1 : n;
            };

            scwin._pickLatestVersion = function(versions) {
                var list = versions || [];
                if (!list.length) { return null; }
                var latest = list[0];
                for (var i = 1; i < list.length; i++) {
                    var cur = list[i];
                    var curNo = scwin._versionSortValue(cur && cur.verNo);
                    var latestNo = scwin._versionSortValue(latest && latest.verNo);
                    if (curNo > latestNo) {
                        latest = cur;
                        continue;
                    }
                    if (curNo === latestNo) {
                        var curId = parseInt(cur && cur.verId, 10);
                        var latestId = parseInt(latest && latest.verId, 10);
                        if (!isNaN(curId) && (isNaN(latestId) || curId > latestId)) {
                            latest = cur;
                        }
                    }
                }
                return latest;
            };


            scwin._openInlineUploadPopup = function(param) {
                var assetId = param && (param.assetId != null ? param.assetId : param.ASSET_ID);
                dmPopup.set("ASSET_ID", assetId ? String(assetId) : "");
                dmPopup.set("VER_ID", "");
                dmPopup.set("FILE_NM", "");
                dmPopup.set("NEW_VER_NO", "");
                 dmPopup.set("POPUP_FILE_TYPE", "");
                dmPopup.set("POPUP_FILE_EXT", "");

                dmPopup.set("CONTRIBUTORS", "");
                dmPopup.set("CHANGE_NOTES", "");
                dmPopup.set("PREVIEW_URL", "/cm/dam/images/preview/document.svg");
                scwin._applyPopupPreview(dmPopup.get("PREVIEW_URL"));
               $p.getComponentById("txt_fb_popup_title").setLabel("Version Info");

                if (assetId) {
                    scwin.callApi("/api/dam/assets/" + encodeURIComponent(assetId), function(res) {
                        if (!res || !res.asset) { return; }
                        var a = res.asset;
                          var latest = scwin._pickLatestVersion(res.versions);
                        var latestVer = latest ? latest.verNo : "";
                        var preview = (latest && latest.previewUrl) ? latest.previewUrl : (a.previewUrl || "/cm/dam/images/preview/document.svg");
                        dmPopup.set("ASSET_ID", String(a.assetId != null ? a.assetId : ""));
                        dmPopup.set("VER_ID", latest && latest.verId != null ? String(latest.verId) : "");
                        dmPopup.set("FILE_NM", a.fileNm || "");
                          dmPopup.set("NEW_VER_NO", latestVer || "");
                        dmPopup.set("POPUP_FILE_TYPE", a.fileType || "");
                        dmPopup.set("POPUP_FILE_EXT", a.fileExt || "");
                        dmPopup.set("CONTRIBUTORS", a.ownerNm || "");
                        dmPopup.set("CHANGE_NOTES", (latest && latest.changeLog) ? latest.changeLog : "");
                        dmPopup.set("PREVIEW_URL", preview);
                          $p.getComponentById("txt_fb_popup_title").setLabel("Version Info: " + (a.fileNm || ""));
                        scwin._applyPopupPreview(preview);
                    });
                }
                var bg = document.getElementById("fbPopupBackdrop");
                if (bg) { bg.style.display = "block"; }
            };


	   scwin._selectedAssetId = null;

            scwin._nextVersionNo = function(currentVerNo) {
                var raw = String(currentVerNo || "").trim();
                var m = raw.match(/^(?:v|V)?(\d+)(?:\.(\d+))?$/);
                var major = 1;
                var minor = 0;
                if (m) {
                    major = parseInt(m[1], 10) || 1;
                    minor = parseInt(m[2] || "0", 10) || 0;
                }
                minor += 1;
                return "v" + major + "." + minor;
            };


            scwin._getDetailValue = function(compId, key) {
                try {
                 var val = null;
                    var c = $p.getComponentById(compId);
                    if (c && typeof c.getValue === "function") {
                         val = c.getValue();
                    }
                } catch (e) {}
                if (val == null || val === "") {
                    try {
                        var el = document.getElementById(compId);
                        if (el && ("value" in el)) { val = el.value; }
                    } catch (e) {}
                }
                if (val == null) { val = dmAssetDetail.get(key); }
                return val == null ? "" : String(val);
            };

            scwin._syncDetailFromForm = function() {
                var keys = [
                    ["inpFileNm", "FILE_NM"],
                    ["taDescription", "DESCRIPTION"],
                    ["inpFileType", "FILE_TYPE"],
                    ["inpTags", "TAGS"],
                    ["selAssetData", "STATUS"],
                    ["inpFileSize", "FILE_SIZE"],
                    ["inpOwnerNm", "OWNER_NM"],
                    ["taChangeLog", "CHANGE_LOG"]
                ];
                for (var i = 0; i < keys.length; i++) {
                    var compId = keys[i][0];
                    var key = keys[i][1];
                    dmAssetDetail.set(key, scwin._getDetailValue(compId, key));
                }
            };

            scwin.btn_asset_detail_submit_onclick = function() {
                var assetId = scwin._selectedAssetId;
                if (!assetId) {
                    alert("Vui lòng chọn asset trước khi submit.");
                    return;
                }
                scwin._syncDetailFromForm();
                  var changeLog = scwin._getDetailValue("taChangeLog", "CHANGE_LOG").trim();
                if (!changeLog) {
                    alert("Change Log là bắt buộc để tạo version mới.");
                    return;
                }
                var rawFileSize = scwin._getDetailValue("inpFileSize", "FILE_SIZE");
                var parsedFileSize = parseInt(String(rawFileSize || "").replace(/[^0-9]/g, ""), 10);
                var assetPayload = {
                    fileNm: scwin._getDetailValue("inpFileNm", "FILE_NM"),
                    description: scwin._getDetailValue("taDescription", "DESCRIPTION"),
                    fileType: scwin._getDetailValue("inpFileType", "FILE_TYPE") || "Documents",
                    tags: scwin._getDetailValue("inpTags", "TAGS"),
                    status: scwin._getDetailValue("selAssetData", "STATUS") || "Draft",
                    ownerNm: scwin._getDetailValue("inpOwnerNm", "OWNER_NM"),
                    fileSize: isNaN(parsedFileSize) ? null : parsedFileSize
                };

                scwin.callApi("/api/dam/assets/" + encodeURIComponent(assetId), function(res) {
                    var latest = scwin._pickLatestVersion(res && res.versions ? res.versions : []);
                    var nextVer = scwin._nextVersionNo(latest ? latest.verNo : "v1.0");
                    if (assetPayload.fileSize == null) { assetPayload.fileSize = (res && res.asset && res.asset.fileSize != null) ? res.asset.fileSize : 0; }
                    var versionPayload = {
                        verNo: nextVer,
                        ownerNm: assetPayload.ownerNm,
                        changeLog: changeLog,
                        previewUrl: (latest && latest.previewUrl) || (res && res.asset && res.asset.previewUrl) || "",
                        fileUrl: assetPayload.fileNm
                    };

                    scwin.callApiJson("PUT", "/api/dam/assets/" + encodeURIComponent(assetId), assetPayload, function(updateRes) {
                        if (!updateRes || Number(updateRes.updated || 0) < 1) {
                            alert("Không cập nhật được thông tin asset trong DB.");
                            return;
                        }
                        scwin.callApiJson("POST", "/api/dam/assets/" + encodeURIComponent(assetId) + "/versions", versionPayload, function(createRes) {
                            if (!createRes || Number(createRes.created || 0) < 1) {
                                alert("Không tạo được version mới trong DB.");
                                return;
                            }
                            alert("Submit thành công. Đã cập nhật asset và tạo version mới: " + nextVer);
                            scwin.loadAssetsByFolder();
                        });
                    });
                });
            };


            scwin.btn_fb_cancel_onclick = function() {
                var bg = document.getElementById("fbPopupBackdrop");
                if (bg) { bg.style.display = "none"; }
            };

            scwin.btn_fb_submit_onclick = function() {
                var assetId = dmPopup.get("ASSET_ID");
                var verId = dmPopup.get("VER_ID");
                if (!assetId) {
                    alert("Không tìm thấy asset để cập nhật.");
                    return;
                }
                var payload = {
                    verNo: dmPopup.get("NEW_VER_NO") || "",
                    ownerNm: dmPopup.get("CONTRIBUTORS") || "",
                    changeLog: dmPopup.get("CHANGE_NOTES") || "",
                    previewUrl: dmPopup.get("PREVIEW_URL") || "",
                    fileUrl: dmPopup.get("FILE_NM") || ""
                };
                   if (!verId) {
                    alert("Không có version trong database để cập nhật.");
                    return;
                }
                var method = "PUT";
                var url = "/api/dam/assets/" + encodeURIComponent(assetId) + "/versions/" + encodeURIComponent(verId);
                scwin.callApiJson(method, url, payload, function() {
                    alert("Cập nhật version thành công.");
                    scwin.btn_fb_cancel_onclick();
                    scwin.loadAssetsByFolder();
                });
            };
